import type { TokenConfig, Palette, ResolvedTokens } from './types'

const CSS_VAR_MAP: Record<string, string> = {
  primary: '--primary',
  primaryForeground: '--primary-foreground',
  secondary: '--secondary',
  secondaryForeground: '--secondary-foreground',
  accent: '--accent',
  accentForeground: '--accent-foreground',
  background: '--background',
  surface: '--surface',
  surfaceLight: '--surface-light',
  text: '--text',
  textLight: '--text-light',
  textMuted: '--text-muted',
  success: '--success',
  error: '--error',
  warning: '--warning',
}

const TYPOGRAPHY_VAR_MAP: Record<string, string> = {
  heading: '--font-heading',
  body: '--font-body',
  headingWeight: '--font-heading-weight',
  bodyWeight: '--font-body-weight',
}

export function resolveTokens(
  config: TokenConfig,
  paletteName?: string
): ResolvedTokens {
  const name = paletteName || config.defaultPalette
  const palette: Palette = config.palettes[name] || config.palettes[config.defaultPalette]

  const colors: Record<string, string> = {}
  for (const [key, cssVar] of Object.entries(CSS_VAR_MAP)) {
    if (palette[key]) {
      colors[cssVar] = palette[key]
    }
  }

  const typography: Record<string, string> = {}
  for (const [key, cssVar] of Object.entries(TYPOGRAPHY_VAR_MAP)) {
    if (config.typography[key]) {
      typography[cssVar] = config.typography[key]
    }
  }

  return { colors, typography, theme: config.theme }
}

export function resolveTokensToCSS(config: TokenConfig, paletteName?: string): string {
  const { colors, typography } = resolveTokens(config, paletteName)
  const lines: string[] = [':root {']

  for (const [varName, value] of Object.entries(colors)) {
    lines.push(`  ${varName}: ${value};`)
  }
  for (const [varName, value] of Object.entries(typography)) {
    lines.push(`  ${varName}: ${value};`)
  }

  if (config.theme === 'dark') {
    lines.push('  color-scheme: dark;')
  }

  lines.push('}')
  return lines.join('\n')
}

export function resolveTokensToStyle(
  config: TokenConfig,
  paletteName?: string
): React.CSSProperties {
  const { colors, typography } = resolveTokens(config, paletteName)
  const style: Record<string, string> = {}

  for (const [key, value] of Object.entries(colors)) {
    style[key] = value
  }
  for (const [key, value] of Object.entries(typography)) {
    style[key] = value
  }

  return style as React.CSSProperties
}
EOF

