export function cleanPhone(phone: string): string {
  return phone.replace(/[\s+()-]/g, '')
}

export function waUrl(
  phone: string,
  message: string,
  source = 'web',
  campaign = 'organic'
): string {
  const clean = cleanPhone(phone)
  const utm = `utm_source=${source}&utm_medium=whatsapp&utm_campaign=${campaign}`
  const text = encodeURIComponent(`${message}\n\n(${utm})`)
  return `https://wa.me/${clean}?text=${text}`
}

export function waCta(
  phone: string,
  service: string,
  source = 'web'
): string {
  return waUrl(phone, `¡Hola! Quiero cotizar ${service}`, source)
}

export function waOrder(
  phone: string,
  orderDetails: string,
  source = 'web'
): string {
  return waUrl(phone, `¡Hola! Quiero hacer un pedido:\n\n${orderDetails}`, source)
}
