'use client'

import React from 'react'
import { usePathname, useSearchParams } from 'next/navigation'
import { useEffect } from 'react'

declare global {
  interface Window {
    dataLayer: unknown[]
    gtag: (...args: unknown[]) => void
  }
}

interface GA4LoaderProps {
  measurementId: string
}

export function GA4Loader({ measurementId }: GA4LoaderProps) {
  useEffect(() => {
    window.dataLayer = window.dataLayer || []
    window.gtag = function (...args: unknown[]) { window.dataLayer.push(args) }
    window.gtag('js', new Date())
    window.gtag('config', measurementId, { send_page_view: false })
  }, [measurementId])

  return (
    <>
      <script async src={`https://www.googletagmanager.com/gtag/js?id=${measurementId}`} />
    </>
  )
}

export function usePageView(measurementId: string) {
  const pathname = usePathname()
  const searchParams = useSearchParams()

  useEffect(() => {
    if (typeof window.gtag === 'function') {
      window.gtag('config', measurementId, {
        page_path: pathname + (searchParams?.toString() ? `?${searchParams}` : ''),
      })
    }
  }, [pathname, searchParams, measurementId])
}

export function trackEvent(action: string, label?: string, value?: number) {
  if (typeof window.gtag === 'function') {
    window.gtag('event', action, { event_label: label, value })
  }
}
