export type Locale = 'es' | 'en' | 'de' | 'nl' | 'pt' | 'gn'

export const LOCALE_NAMES: Record<Locale, string> = {
  es: 'Español',
  en: 'English',
  de: 'Deutsch',
  nl: 'Nederlands',
  pt: 'Português',
  gn: 'Guaraní',
}

export function localeFromPath(pathname: string): Locale | null {
  const match = pathname.match(/^\/(es|en|de|nl|pt|gn)(\/|$)/)
  return match ? (match[1] as Locale) : null
}

export function localeHref(href: string, locale: Locale, defaultLocale: Locale = 'es'): string {
  if (locale === defaultLocale) return href.replace(/^\/(es|en|de|nl|pt|gn)/, '') || '/'
  return `/${locale}${href}`
}

export function alternatesFor(
  pathname: string,
  baseUrl: string,
  locales: Locale[],
  defaultLocale: Locale = 'es'
): Record<string, string> {
  const alternates: Record<string, string> = {}
  for (const l of locales) {
    const path = l === defaultLocale ? pathname.replace(/^\/(es|en|de|nl|pt|gn)/, '') : `/${l}${pathname}`
    alternates[l] = `${baseUrl}${path}`
  }
  return alternates
}

// Currency formatting for Paraguayan use
const CURRENCY_FORMATTERS: Record<string, Intl.NumberFormat> = {
  PYG: new Intl.NumberFormat('es-PY', { style: 'currency', currency: 'PYG', minimumFractionDigits: 0, maximumFractionDigits: 0 }),
  USD: new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }),
  EUR: new Intl.NumberFormat('de-DE', { style: 'currency', currency: 'EUR' }),
}

export function formatCurrency(amount: number, currency: 'PYG' | 'USD' | 'EUR' = 'PYG'): string {
  return CURRENCY_FORMATTERS[currency]?.format(amount) || `${currency} ${amount.toLocaleString()}`
}

export function formatDate(date: Date | string, locale: Locale = 'es'): string {
  const d = typeof date === 'string' ? new Date(date) : date
  return d.toLocaleDateString(locale === 'es' ? 'es-PY' : locale, {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  })
}
