import type { SiteDefinition, PageDefinition, ResolvedPage, PageSection, Locale } from './types'
import { resolveSectionAlias, defaultVariant } from './registry'

export interface ComposeOptions {
  site: SiteDefinition
  locale: Locale
  pageDef: PageDefinition
  seo?: {
    title?: string
    description?: string
    ogImage?: string
  }
  theme?: { isDark: boolean; palette: string }
