export function composePage(opts: ComposeOptions): ResolvedPage {
  const sections: PageSection[] = opts.pageDef.sections.map((s, i) => ({
    id: resolveSectionAlias(s.id),
    variant: s.variant || defaultVariant(s.id),
    order: i,
    props: s.data || {},
  }))

  return {
