    },
    theme: opts.theme || { isDark: false, palette: 'default' },
  }
}

export function fillTemplate(template: string, data: Record<string, string | number>): string {
  return template.replace(/\{\{(\w+)\}\}/g, (_, key) => {
    const val = data[key]
    return val !== undefined ? String(val) : `{{${key}}}`
  })
}
