import React from 'react'
import type { ResolvedPage, PageSection } from './types'

export interface RendererConfig {
  components: Record<string, React.ComponentType<any>>
  fallback?: React.ComponentType<{ section: PageSection }>
}

export function renderSections(
  page: ResolvedPage,
  components: Record<string, React.ComponentType<any>>,
  SectionWrapper?: React.ComponentType<{ children: React.ReactNode; section: PageSection; index: number }>
): React.ReactNode[] {
  return page.sections.map((s, i) => {
    const Component = components[s.id]
    if (!Component) return null

    const sectionEl = (
      <Component
        key={`${s.id}-${i}`}
        {...s.props}
        variant={s.variant}
        locale={page.locale}
      />
    )

    if (SectionWrapper) {
      return (
        <SectionWrapper key={`${s.id}-${i}`} section={s} index={i}>
          {sectionEl}
        </SectionWrapper>
      )
    }

    return sectionEl
  }).filter(Boolean) as React.ReactNode[]
}

export function DefaultSectionWrapper({
  children,
  section,
  index,
}: {
  children: React.ReactNode
  section: PageSection
  index: number
}) {
  const bgCycle = index % 3 === 0 ? 'var(--background)' : index % 3 === 1 ? 'var(--surface)' : 'var(--surface-light)'
  return (
    <section
      style={{
        backgroundColor: bgCycle,
        padding: '4rem 0',
        borderTop: index > 0 && index % 3 !== 0 ? '1px solid var(--surface-light)' : undefined,
      }}
    >
      {children}
    </section>
  )
}
