  loadSite(slug: string): SiteDefinition | null
  loadPage(siteSlug: string, pageSlug: string): PageDefinition | null
  listPages(siteSlug: string): string[]
  listSites(): string[]
}

export function createMemoryLoader(
  sites: Record<string, SiteDefinition>,
  pages: Record<string, Record<string, PageDefinition>>
): SiteLoader {
  return {
    loadSite(slug) { return sites[slug] || null },
    loadPage(siteSlug, pageSlug) { return pages[siteSlug]?.[pageSlug] || null },
    listPages(siteSlug) { return Object.keys(pages[siteSlug] || {}) },
