import type { Cart, CartItem, CartTotals } from './types'

export function createCart(currency: 'PYG' | 'USD' = 'PYG'): Cart {
  return {
    items: [],
    currency,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  }
}

export function addItem(cart: Cart, item: CartItem): Cart {
  const existing = cart.items.find(i => i.productId === item.productId && i.variant === item.variant)
  if (existing) {
    existing.quantity += item.quantity
    if (existing.maxQuantity && existing.quantity > existing.maxQuantity) {
      existing.quantity = existing.maxQuantity
    }
  } else {
    cart.items.push({ ...item })
  }
  cart.updatedAt = new Date().toISOString()
  return { ...cart, items: [...cart.items] }
}

export function removeItem(cart: Cart, productId: string): Cart {
  return {
    ...cart,
    items: cart.items.filter(i => i.productId !== productId),
    updatedAt: new Date().toISOString(),
  }
}

export function updateQuantity(cart: Cart, productId: string, quantity: number): Cart {
  const item = cart.items.find(i => i.productId === productId)
  if (!item) return cart
  item.quantity = Math.max(0, quantity)
  if (item.maxQuantity && item.quantity > item.maxQuantity) {
    item.quantity = item.maxQuantity
  }
  cart.updatedAt = new Date().toISOString()
  return { ...cart, items: cart.items.filter(i => i.quantity > 0) }
}

export function clearCart(cart: Cart): Cart {
  return { ...cart, items: [], coupon: undefined, discount: undefined, shipping: undefined, updatedAt: new Date().toISOString() }
}

export function calculateTotals(cart: Cart): CartTotals {
  const subtotal = cart.items.reduce((sum, i) => sum + i.price * i.quantity, 0)
  const discount = cart.discount || 0
  const shipping = cart.shipping || 0
  const tax = 0 // Paraguay doesn't apply IVA to most products at point of sale
  return {
    subtotal,
    discount,
    shipping,
    tax,
    total: Math.max(0, subtotal - discount + shipping + tax),
  }
}

export function itemCount(cart: Cart): number {
  return cart.items.reduce((sum, i) => sum + i.quantity, 0)
}

export function serializeCart(cart: Cart): string {
  return JSON.stringify(cart)
}

export function deserializeCart(data: string): Cart | null {
  try {
    const cart = JSON.parse(data) as Cart
    return cart.items ? cart : null
  } catch {
    return null
  }
}
EOF

