// Paraguayan peso formatting and price utilities

export const CURRENCY_SYMBOLS: Record<string, string> = {
  PYG: 'Gs.',
  USD: 'US$',
}

export function formatPrice(amount: number, currency: 'PYG' | 'USD' = 'PYG'): string {
  if (currency === 'PYG') {
    return `Gs. ${Math.round(amount).toLocaleString('es-PY')}`
  }
  return `US$ ${amount.toFixed(2)}`
}

export function parsePrice(input: string): number {
  const cleaned = input.replace(/[^0-9.,]/g, '').replace(/\./g, '').replace(',', '.')
  return parseFloat(cleaned) || 0
}

export function applyDiscount(price: number, discountPercent: number): number {
  return price * (1 - discountPercent / 100)
}

export function calculateInstallment(price: number, months: number, interestRate: number = 0): number {
  if (interestRate === 0) return price / months
  const monthlyRate = interestRate / 100 / 12
  return (price * monthlyRate * Math.pow(1 + monthlyRate, months)) / (Math.pow(1 + monthlyRate, months) - 1)
}
EOF

