export default function Tienda() {
  const [selectedCat, setSelectedCat] = useState<string | null>(null)
  const products = selectedCat ? content.products.filter(p => p.category === selectedCat) : content.products

  return (
    <div style={{ maxWidth: 1200, margin: "0 auto", padding: "40px 16px" }}>
      <h1 style={{ fontSize: "1.8rem", fontWeight: 700, marginBottom: 8 }}>{content.navigation.tienda}</h1>
      <p style={{ color: "var(--color-text-muted)", marginBottom: 32 }}>{content.hero.subheadline}</p>

      <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 32 }}>
        <button onClick={() => setSelectedCat(null)} style={{
          padding: "8px 16px", borderRadius: 8, border: "1px solid var(--color-surface-light)",
          background: !selectedCat ? "var(--color-primary)" : "transparent",
          color: !selectedCat ? "white" : "var(--color-text-light)",
          cursor: "pointer", fontWeight: 600, fontSize: "0.85rem",
        }}>Todos</button>
        {content.categories.map(cat => (
          <button key={cat.id} onClick={() => setSelectedCat(cat.id)} style={{
            padding: "8px 16px", borderRadius: 8, border: "1px solid var(--color-surface-light)",
            background: selectedCat === cat.id ? "var(--color-primary)" : "transparent",
            color: selectedCat === cat.id ? "white" : "var(--color-text-light)",
            cursor: "pointer", fontWeight: 500, fontSize: "0.85rem",
          }}>{cat.name}</button>
        ))}
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))", gap: 20 }}>
        {products.map(p => <ProductCard key={p.id} {...p} />)}
      </div>
      {products.length === 0 && <p style={{ textAlign: "center", color: "var(--color-text-muted)", padding: 40 }}>No hay productos en esta categoría.</p>}
    </div>
