        ('<FAQJsonLd questions={content.faq.map(f => ({ question: f.q, answer: f.a }))} />', ''),
    ],
    "components/product-card.tsx": [
        ('import { formatPrice } from "@ai-whisperers/commerce"', ''),
    ],
    "components/seo.tsx": [
        ('import { LocalBusinessJsonLd, FAQJsonLd } from "@ai-whisperers/seo"', ''),
    ],
}

for filepath, replacements in imports_to_fix.items():
    content = open(f"{f_path}/{filepath}").read()
    for old, new in replacements:
        content = content.replace(old, new)
    open(f"{f_path}/{filepath}", 'w').write(content)

# Implement formatPrice inline in product-card
open(f"{f_path}/components/product-card.tsx", 'w').write("""'use client'
import Link from "next/link"

function formatPrice(amount: number, currency: string) {
  if (currency === "PYG") return `Gs. ${Math.round(amount).toLocaleString("es-PY")}`
  return `US$ ${amount.toFixed(2)}`
}

interface ProductCardProps {
  id: number; name: string; price: number; image: string; category: string; featured?: boolean
}

export function ProductCard({ id, name, price, image, category, featured }: ProductCardProps) {
  return (
    <Link href={`/producto/${id}`} style={{ textDecoration: "none" }}>
      <div style={{
        background: "var(--color-surface, #1A1A2E)", borderRadius: 16, overflow: "hidden",
        border: featured ? "2px solid var(--color-accent, #EC4899)" : "1px solid var(--color-surface-light, #252540)",
        transition: "transform 0.2s, box-shadow 0.2s", cursor: "pointer",
      }}
        onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-4px)"; e.currentTarget.style.boxShadow = "0 8px 24px rgba(124,58,237,0.2)" }}
        onMouseLeave={e => { e.currentTarget.style.transform = "translateY(0)"; e.currentTarget.style.boxShadow = "none" }}
      >
        <div style={{ height: 200, background: "linear-gradient(135deg, var(--color-surface-light), var(--color-surface))", display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center", color: "var(--color-primary)", fontSize: "3rem", opacity: 0.3 }}>✦</div>
        </div>
        <div style={{ padding: 16 }}>
          {featured && <span style={{ background: "var(--color-accent)", color: "white", fontSize: "0.7rem", fontWeight: 600, padding: "2px 8px", borderRadius: 4 }}>Destacado</span>}
          <h3 style={{ color: "var(--color-text)", fontSize: "0.95rem", fontWeight: 600, margin: "8px 0 4px", lineHeight: 1.3 }}>{name}</h3>
          <p style={{ color: "var(--color-primary)", fontSize: "1.1rem", fontWeight: 700, margin: 0 }}>{formatPrice(price, "PYG")}</p>
        </div>
      </div>
    </Link>
  )
}
""")

# Fix producto/[id]/page.tsx to not use packages
open(f"{f_path}/app/producto/[id]/page.tsx", 'w').write("""'use client'
import { useParams } from "next/navigation"
import content from "@/content/es.json"
import Link from "next/link"

function formatPrice(amount: number) { return `Gs. ${Math.round(amount).toLocaleString("es-PY")}` }
function cleanPhone(p: string) { return p.replace(/[\\s+()-]/g, "") }
function waUrl(phone: string, msg: string) {
  return `https://wa.me/${cleanPhone(phone)}?text=${encodeURIComponent(msg)}`
}

export default function ProductDetail() {
  const { id } = useParams()
  const product = content.products.find(p => p.id === Number(id))
  if (!product) return <div style={{ padding: 80, textAlign: "center" }}><h2>Producto no encontrado</h2><Link href="/tienda" style={{ color: "var(--color-primary)" }}>Volver a la tienda</Link></div>
  const waMsg = waUrl("+595********", `¡Hola! Quiero comprar: ${product.name} — ${formatPrice(product.price)}`)
  return (
    <div style={{ maxWidth: 1000, margin: "0 auto", padding: "40px 16px" }}>
      <Link href="/tienda" style={{ color: "var(--color-primary)", textDecoration: "none", fontSize: "0.85rem", display: "inline-block", marginBottom: 24 }}>← Volver a la tienda</Link>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 40, alignItems: "start" }}>
        <div style={{ background: "linear-gradient(135deg, var(--color-surface-light), var(--color-surface))", borderRadius: 20, height: 400, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ fontSize: "5rem", opacity: 0.15 }}>✦</div>
        </div>
        <div>
          <h1 style={{ fontSize: "1.8rem", fontWeight: 700, marginBottom: 8 }}>{product.name}</h1>
          <p style={{ fontSize: "1.5rem", fontWeight: 700, color: "var(--color-primary)", marginBottom: 20 }}>{formatPrice(product.price)}</p>
          <p style={{ color: "var(--color-text-light)", lineHeight: 1.7, marginBottom: 24 }}>{product.description}</p>
          <h3 style={{ fontSize: "1rem", fontWeight: 600, marginBottom: 12 }}>Características:</h3>
          <ul style={{ padding: 0, listStyle: "none", marginBottom: 32 }}>
            {product.features.map((f, i) => (
              <li key={i} style={{ padding: "8px 0", borderBottom: "1px solid var(--color-surface-light)", color: "var(--color-text-light)", fontSize: "0.9rem" }}>✓ {f}</li>
            ))}
          </ul>
          <a href={waMsg} target="_blank" rel="noopener noreferrer" style={{ display: "inline-block", background: "#25D366", color: "white", padding: "14px 32px", borderRadius: 12, fontWeight: 600, textDecoration: "none", fontSize: "1rem" }}>Comprar por WhatsApp</a>
        </div>
      </div>
    </div>
  )
}
""")

